example.code:
// Client Secret authentication
var authOption = new AuthenticationOption
{
    Mode = AuthenticationMode.ClientSecret,
    TenantId = "your-tenant-id",
    ClientId = "your-client-id",
    ClientSecret = "your-client-secret"
};
var credential = CredentialFactory.CreateCredential(authOption);

// Managed Identity authentication
var authOption = new AuthenticationOption
{
    Mode = AuthenticationMode.ManagedIdentity
};
var credential = CredentialFactory.CreateCredential(authOption);

var authOption = new AuthenticationOption
{
    Mode = AuthenticationMode.ClientSecret,
    TenantId = "your-tenant-id",
    ClientId = "your-client-id",
    ClientSecret = "your-secret"
};
var credential = CredentialFactory.CreateCredential(authOption);
var blobClient = new BlobServiceClient(new Uri("https://account.blob.core.windows.net"), credential);

member.summary:
Converts a SecureString to a plain string at the point of use.
The returned string lives on the managed heap and cannot be pinned/zeroed;
this is an inherent .NET limitation as Azure SDK classes require plain strings.

example.code:
// Detect from connection string
var provider = ProviderDetector.DetectProvider(
    disk: false,
    inMemory: false,
    connectionString: "DefaultEndpointsProtocol=https;AccountName=myaccount;...",
    containerName: "mycontainer");
// Result: DataProvider.AzureBlob

// Detect from parameters
var provider = ProviderDetector.DetectProvider(
    queueName: "myqueue",
    containerName: null);
// Result: DataProvider.AzureQueue

var provider = ProviderDetector.DetectProvider(
    disk: false,
    inMemory: false,
    connectionString: "DefaultEndpointsProtocol=https;AccountName=storage;...",
    containerName: "mycontainer",
    warningCallback: msg => Console.WriteLine($"Warning: {msg}"));

member.summary:
Abstraction over repository session management for testability.
Production code uses the static  directly;
this interface enables unit-testing cmdlets without live Azure connections.

example.code:
var options = new StorageOption
{
    RepositoryIdentity = "mykeyvault",  // Vault name or full URI
    ProviderName = "AzureKeyVault",
    Authentication = new AuthenticationOption
    {
        Mode = AuthenticationMode.ManagedIdentity
    }
};
var repository = new AzureKeyVaultRepository(options);
await repository.SetSecretAsync("MySecret", "SecretValue123");
var value = await repository.GetSecretAsync("MySecret");

var value = await repository.GetSecretAsync("DatabaseConnectionString");
if (value != null)
{
    Console.WriteLine($"Retrieved secret: {SecurityHelper.MaskSensitiveData(value)}");
}
